ts": "Active ingredient: Kasugamycin 6%", "spec": "500 grams", "how_to_use": "Though primarily for rice diseases, Kasugamycin can be applied by diluting 45 grams with 30 jin of water and spraying on tomato plants showing bacterial symptoms to reduce bacterial load.", "frequency": "Apply once every 7-10 days for 2-3 consecutive applications if symptoms persist.", "caution": "Do not apply if rain is expected within 3 hours to avoid wash-off; reapply if rain occurs.", "match_score": 0.486, "source": "rag"}, {"product_id": "PN0007", "name": "3% Metalaxyl-Hymexazol", "product_type": "pesticide", "ingredients": "Active ingredients: Hymexazol 2.5%, Metalaxyl 0.5%; Total active ingredients: Metalaxyl-M 3% (Active ingredients and their contents: Hymexazol 2.5%, Metalaxyl 0.5%)", "spec": "1000g/500g/100g", "how_to_use": "Dilute 100 grams of 3% Metalaxyl-Hymexazol with 30 jin of water and spray on soil and plant surfaces around tomato plants to help control fungal pathogens that may complicate bacterial rot.", "frequency": "Apply up to 3 times per season with a minimum safety interval of 3 days between applications.", "caution": "Use as a preventive measure and avoid overuse to reduce risk of resistance development.", "match_score": 0.4262, "source": "rag"}]
